   155→  // GET /api/sessions
   156→  app.get("/api/sessions", async (_req, res) => {
   157→    try {
   158→      const sessions = await db.session.findMany({
   159→        orderBy: { updatedAt: "desc" },
   160→      });
   161→      const sessionIds = sessions.map((s) => s.sessionId);
   162→
   163→      // Fetch latest branch and intent per session from CheckpointSessionMetadata
   164→      const sessionMetas = await db.checkpointSessionMetadata.findMany({
   165→        where: { sessionId: { in: sessionIds } },
   166→        select: { sessionId: true, branch: true, createdAt: true, summary: { select: { intent: true } } },
   167→        orderBy: { createdAt: "desc" },
   168→      });
   169→      const branchMap = new Map<string, string | null>();
   170→      const intentMap = new Map<string, string | null>();
   171→      for (const m of sessionMetas) {
   172→        if (!branchMap.has(m.sessionId)) branchMap.set(m.sessionId, m.branch);
   173→        if (!intentMap.has(m.sessionId)) intentMap.set(m.sessionId, m.summary?.intent ?? null);
   174→      }
   175→
   176→      // Build parent → children map in memory
   177→      const childMap = new Map<string, string[]>();
   178→      for (const s of sessions) {
