   180→          const arr = childMap.get(s.parentSessionId) ?? [];
   181→          arr.push(s.sessionId);
   182→          childMap.set(s.parentSessionId, arr);
   183→        }
   184→      }
   185→      res.json(sessions.map((s) => mapSession(s, childMap.get(s.sessionId) ?? [], branchMap.get(s.sessionId) ?? null, intentMap.get(s.sessionId) ?? null)));
