   655→  app.post("/api/sessions/spawn", async (req, res) => {
   656→    const { prompt, cwd, openItemIds, parentSessionId } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[]; parentSessionId?: string };
   657→    if (!prompt || typeof prompt !== "string") {
   658→      res.status(400).json({ error: "prompt is required" });
   659→      return;
   660→    }
   661→    try {
   662→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   663→      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   664→      // Pass open item IDs and parent session so the SessionStart hook can link back
   665→      const envParts: string[] = [];
   666→      if (openItemIds?.length) envParts.push(`GOSSAMER_SPAWN_OPEN_ITEMS='${openItemIds.join(",")}'`);
   667→      if (parentSessionId) envParts.push(`GOSSAMER_SPAWN_PARENT_SESSION='${parentSessionId.replace(/'/g, "")}'`);
   668→      const envPrefix = envParts.length ? envParts.join(" ") + " " : "";
   669→      // Use AppleScript to open a new Terminal window running claude interactively
   670→      const script = [
   671→        `tell application "Terminal"`,
   672→        `  activate`,
   673→        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   674→        `end tell`,
   675→      ].join("\n");
   676→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   677→      // Mark selected open items as in_progress
   678→      if (openItemIds?.length) {
   679→        await db.openItem.updateMany({
   680→          where: { id: { in: openItemIds } },
   681→          data: { status: "in_progress" },
   682→        });
   683→      }
   684→      res.json({ started: true });
