   704→  // Create HTTP server and attach WebSocket server (shared port)
   705→  const httpServer = createServer(app);
   706→  const wss = new WebSocketServer({ server: httpServer });
   707→
   708→  // WebSocket change detection — poll every 2s, broadcast on new events or checkpoints
   709→  let lastMaxEventId: number | null = null;
   710→  let lastMaxCheckpointId: number | null = null;
   711→  const broadcast = () => {
   712→    const message = JSON.stringify({ type: "sessions_updated" });
   713→    for (const client of wss.clients) {
   714→      if (client.readyState === WebSocket.OPEN) {
   715→        client.send(message);
   716→      }
   717→    }
   718→  };
   719→  const poller = setInterval(async () => {
   720→    try {
   721→      const [latestEvent, latestCheckpoint] = await Promise.all([
   722→        db.event.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   723→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   724→      ]);
   725→      const currentEventId = latestEvent?.id ?? null;
   726→      const currentCheckpointId = latestCheckpoint?.id ?? null;
   727→      if (currentEventId !== lastMaxEventId || currentCheckpointId !== lastMaxCheckpointId) {
   728→        lastMaxEventId = currentEventId;
   729→        lastMaxCheckpointId = currentCheckpointId;
   730→        broadcast();
   731→      }
   732→    } catch {
   733→      // Non-fatal polling error — keep running
   734→    }
   735→  }, 2000);
