   737→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   738→
   739→  const WORKTREE_PATH = "/tmp/gossamer-checkpoints";
   740→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   741→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   742→
   743→  if (repoDir) {
   744→    // Ensure worktree exists (reuse across restarts)
   745→    if (!existsSync(WORKTREE_PATH)) {
   746→      try {
   747→        // Prune stale worktree registration first, then re-add
   748→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   749→        execSync(
   750→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   751→          { stdio: "pipe" },
   752→        );
   753→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   754→      } catch (err) {
   755→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   756→      }
   757→    }
   758→
   759→    const runIndex = async () => {
   760→      if (!existsSync(WORKTREE_PATH)) return;
   761→      try {
   762→        // Fetch latest commits and advance the worktree to the branch tip
   763→        execSync(
   764→          `git -C ${JSON.stringify(WORKTREE_PATH)} fetch origin ${CHECKPOINT_BRANCH}`,
   765→          { stdio: "pipe" },
   766→        );
   767→        execSync(
   768→          `git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard FETCH_HEAD`,
   769→          { stdio: "pipe" },
   770→        );
   771→      } catch { /* non-fatal */ }
   772→      try {
   773→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH, undefined, repoDir);
   774→        if (checkpoints > 0) {
   775→          process.stderr.write(`checkpoint indexer: indexed ${checkpoints} checkpoints\n`);
   776→          broadcast();
   777→        }
   778→      } catch { /* non-fatal */ }
   779→    };
   780→
   781→    void runIndex();
   782→    checkpointPoller = setInterval(runIndex, 30_000);
   783→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   784→  }
   785→
   786→  // Graceful shutdown
   787→  const shutdown = () => {
   788→    clearInterval(poller);
   789→    if (checkpointPoller) clearInterval(checkpointPoller);
   790→    httpServer.close();
   791→    process.exit(0);
   792→  };
   793→  process.on("SIGINT", shutdown);
   794→  process.on("SIGTERM", shutdown);
   795→
   796→  await new Promise<void>((resolve) => {
   797→    httpServer.listen(port, () => {
   798→      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   799→      resolve();
   800→    });
   801→  });
   802→}
