    38→// ─── Singleton DB cache ───────────────────────────────────────────────────────
    39→
    40→const dbCache = new Map<string, PrismaClient>();
    41→
    42→/**
    43→ * Open (or return cached) a PrismaClient backed by a better-sqlite3 file at `dbPath`.
    44→ * Runs PRAGMA journal_mode=WAL for safe concurrent writes.
    45→ */
    46→export async function getDb(dbPath: string): Promise<PrismaClient> {
    47→  const abs = resolve(dbPath);
    48→  const cached = dbCache.get(abs);
    49→  if (cached) return cached;
    50→
    51→  mkdirSync(dirname(abs), { recursive: true });
    52→
    53→  const adapter = new PrismaBetterSqlite3({ url: `file:${abs}` });
    54→  const db = new PrismaClient({ adapter } as ConstructorParameters<typeof PrismaClient>[0]);
    55→
    56→  try {
    57→    await db.$queryRawUnsafe("PRAGMA journal_mode=WAL");
    58→  } catch {
    59→    // Non-fatal — WAL mode is a performance hint
    60→  }
    61→
    62→  dbCache.set(abs, db);
    63→  return db;
    64→}
