    68→/** Read all session state tables and assemble an in-memory State object. */
    69→export async function readStateFromDb(db: PrismaClient): Promise<State> {
    70→  const [sessions, agentParents, pendingToolUses] = await Promise.all([
    71→    db.session.findMany(),
    72→    db.agentParent.findMany(),
    73→    db.pendingToolUse.findMany(),
    74→  ]);
    75→
    76→  const sessionMap: Record<string, SessionRecord> = {};
    77→  for (const s of sessions) {
    78→    sessionMap[s.sessionId] = {
    79→      sessionId: s.sessionId,
    80→      startedAt: s.startedAt instanceof Date ? s.startedAt.toISOString() : String(s.startedAt),
    81→      updatedAt: s.updatedAt instanceof Date ? s.updatedAt.toISOString() : String(s.updatedAt),
    82→      cwd: s.cwd,
    83→      repoRoot: s.repoRoot ?? undefined,
    84→      repoName: s.repoName ?? undefined,
    85→      parentSessionId: s.parentSessionId ?? undefined,
    86→      gitUserName: s.gitUserName ?? undefined,
    87→      gitUserEmail: s.gitUserEmail ?? undefined,
    88→      prompt: s.prompt ?? undefined,
    89→      summary: s.summary ?? undefined,
    90→      keywords: s.keywords ? (JSON.parse(s.keywords) as string[]) : undefined,
    91→    };
    92→  }
    93→
    94→  const agentParentMap: Record<string, string> = {};
    95→  for (const ap of agentParents) {
    96→    agentParentMap[ap.agentId] = ap.parentSessionId;
    97→  }
    98→
    99→  const pendingMap: Record<string, PendingToolUseRecord> = {};
   100→  for (const p of pendingToolUses) {
   101→    pendingMap[p.toolUseId] = {
   102→      tool_use_id: p.toolUseId,
   103→      tool_name: p.toolName,
   104→      tool_input: p.toolInput ? (JSON.parse(p.toolInput) as unknown) : undefined,
   105→      startedAt: p.startedAt,
   106→    };
   107→  }
   108→
   109→  return { sessions: sessionMap, agentParents: agentParentMap, pendingToolUses: pendingMap };
   110→}
