     1→/**
     2→ * Entire CLI checkpoint indexer.
     3→ *
     4→ * Reads the shard-tree produced by `entire commit` on the `entire/checkpoints/v1`
     5→ * branch and writes Checkpoint / CheckpointSession / CheckpointMessage records
     6→ * into the SQLite database.
     7→ *
     8→ * Directory layout expected under the root:
     9→ *   <root>/<shard2>/<id10>/metadata.json
    10→ *   <root>/<shard2>/<id10>/0/metadata.json
    11→ *   <root>/<shard2>/<id10>/0/full.jsonl
    12→ *   <root>/<shard2>/<id10>/1/metadata.json    (if multiple sessions)
    13→ *   <root>/<shard2>/<id10>/1/full.jsonl
    14→ *   ...
    15→ */
    16→
    17→import { readdirSync, readFileSync, existsSync, statSync } from "fs";
    18→import { join } from "path";
    19→import type { PrismaClient } from "../prisma/generated/client/index.js";
    20→import { findCommitForCheckpoint } from "./gitUtils.js";
    21→import { setupLogContentFts, syncLogContentFts } from "./search.js";
    22→
    23→// ─── Raw shapes from the checkpoint files ─────────────────────────────────────
    24→
    25→interface RootMeta {
    26→  cli_version?: string;
    27→  checkpoint_id?: string;
    28→  strategy?: string;
    29→  branch?: string;
    30→  checkpoints_count?: number;
    31→  files_touched?: string[];
    32→  token_usage?: Record<string, unknown>;
    33→}
    34→
    35→interface SummaryLearnings {
    36→  repo?: string[];
    37→  code?: Array<{ path: string; finding: string }>;
    38→  workflow?: string[];
    39→}
    40→
    41→interface SessionSummary {
    42→  intent?: string;
    43→  outcome?: string;
    44→  learnings?: SummaryLearnings;
    45→  friction?: string[];
    46→  open_items?: string[];
    47→}
    48→
    49→interface SessionMeta {
    50→  session_id: string;
    51→  checkpoint_id?: string;
    52→  cli_version?: string;
    53→  strategy?: string;
    54→  created_at?: string;
    55→  branch?: string;
    56→  checkpoints_count?: number;
    57→  turn_id?: string;
    58→  agent?: string;
    59→  token_usage?: Record<string, unknown>;
    60→  initial_attribution?: Record<string, unknown>;
    61→  files_touched?: string[];
    62→  summary?: SessionSummary;
    63→  checkpoint_transcript_start?: number;
    64→  transcript_lines_at_start?: number;
    65→}
    66→
    67→// A single line from full.jsonl — fields vary by type
    68→export interface FullJsonlEvent {
    69→  uuid?: string;
    70→  messageId?: string;      // used by "file-history-snapshot" instead of uuid
    71→  sessionId?: string;
    72→  parentUuid?: string;
    73→  type: string;
    74→  timestamp?: string;
    75→  cwd?: string;
    76→  gitBranch?: string;
    77→  slug?: string;
    78→  version?: string;
    79→  planContent?: string;
    80→  toolUseID?: string;
    81→  parentToolUseID?: string;
    82→  isSidechain?: boolean;
    83→  userType?: string;
    84→  message?: unknown;
    85→  data?: unknown;
    86→  [key: string]: unknown;
    87→}
    88→
    89→// ─── Parsing ──────────────────────────────────────────────────────────────────
    90→
    91→/**
    92→ * Parse a full.jsonl string into an array of event objects.
    93→ * Malformed lines are silently skipped.
    94→ */
    95→export function parseFullJsonl(content: string): FullJsonlEvent[] {
    96→  const out: FullJsonlEvent[] = [];
    97→  for (const line of content.split("\n")) {
    98→    const trimmed = line.trim();
    99→    if (!trimmed) continue;
   100→    try {
   101→      out.push(JSON.parse(trimmed) as FullJsonlEvent);
   102→    } catch {
   103→      // skip malformed line
   104→    }
   105→  }
   106→  return out;
   107→}
   108→
   109→/** Return the unique key for an event, preferring uuid then messageId. */
   110→function eventKey(e: FullJsonlEvent): string | null {
   111→  return e.uuid ?? e.messageId ?? null;
   112→}
   113→
   114→// ─── Git OID mapping helper ───────────────────────────────────────────────────
   115→
   116→async function saveGitOidMapping(
   117→  db: PrismaClient,
   118→  checkpointId: string,
   119→  branch: string | null | undefined,
   120→  repoPath: string,
   121→  existingMappings?: Map<string, string>,
   122→): Promise<void> {
   123→  if (!branch) return;
   124→  try {
   125→    const commit = await findCommitForCheckpoint(repoPath, branch, checkpointId);
   126→    if (!commit) return;
   127→    const existingOid = existingMappings?.get(checkpointId);
   128→    if (existingOid === commit.hash) return; // exact (checkpointId, gitOid) pair already recorded
   129→    // OID is new or changed (e.g. after rebase) — replace old entry if present
   130→    if (existingOid) {
   131→      await db.checkpointIdGitOidJoin.delete({ where: { gitOid: existingOid } }).catch(() => {});
   132→    }
   133→    await db.checkpointIdGitOidJoin.upsert({
   134→      where: { gitOid: commit.hash },
   135→      create: { gitOid: commit.hash, checkpointId },
   136→      update: { checkpointId },
   137→    });
   138→    existingMappings?.set(checkpointId, commit.hash);
   139→  } catch {
   140→    // non-fatal — git may not be available or branch may not exist
   141→  }
   142→}
   143→
   144→// ─── Single-checkpoint indexer ────────────────────────────────────────────────
   145→
   146→/**
   147→ * Index one checkpoint directory (the folder named by the last 10 hex chars,
   148→ * e.g. `<root>/0c/b6cf391c40`).
   149→ *
   150→ * @returns Number of new messages written (already-indexed events are skipped).
   151→ */
   152→
   153→// ─── V2 helpers ───────────────────────────────────────────────────────────────
   154→
   155→async function upsertFilePath(db: PrismaClient, path: string): Promise<number> {
   156→  const existing = await db.filePath.findUnique({ where: { path }, select: { id: true } });
   157→  if (existing) return existing.id;
   158→  const created = await db.filePath.create({ data: { path } });
   159→  return created.id;
   160→}
   161→
   162→async function createTokenUsage(db: PrismaClient, tu: Record<string, unknown>): Promise<number> {
   163→  const row = await db.tokenUsage.create({
   164→    data: {
   165→      inputTokens:         Number(tu.input_tokens          ?? 0),
   166→      cacheCreationTokens: Number(tu.cache_creation_tokens ?? 0),
   167→      cacheReadTokens:     Number(tu.cache_read_tokens     ?? 0),
   168→      outputTokens:        Number(tu.output_tokens         ?? 0),
   169→      apiCallCount:        Number(tu.api_call_count        ?? 0),
   170→    },
   171→  });
   172→  return row.id;
   173→}
   174→
   175→// ─── V2 single-checkpoint indexer ────────────────────────────────────────────
   176→
   177→/**
   178→ * Index one checkpoint directory using the new normalized schema.
   179→ *
   180→ * Reads:
   181→ *   <checkpointDir>/metadata.json             → CheckpointMetadata
   182→ *   <checkpointDir>/<n>/metadata.json         → CheckpointSessionMetadata
   183→ *   <checkpointDir>/<n>/content_hash.txt      → SessionLink.contentHash (actual hash)
   184→ *   <checkpointDir>/<n>/{full.jsonl,context.md,prompt.txt} → SessionLink paths
   185→ */
   186→export async function indexCheckpointV2(
   187→  db: PrismaClient,
   188→  checkpointDir: string,
   189→  checkpointId: string,
   190→  repoPath?: string,
   191→  mappedCheckpointIds?: Set<string>,
   192→): Promise<void> {
   193→  const metaPath = join(checkpointDir, "metadata.json");
   194→  if (!existsSync(metaPath)) throw new Error(`No metadata.json at ${checkpointDir}`);
   195→
   196→  const meta = JSON.parse(readFileSync(metaPath, "utf8")) as RootMeta;
   197→
   198→  // Upsert CheckpointMetadata — create TokenUsage only on first insert
   199→  let checkpointMeta = await db.checkpointMetadata.findUnique({
   200→    where: { checkpointId },
   201→    select: { id: true },
   202→  });
   203→
   204→  if (!checkpointMeta) {
   205→    let tokenUsageId: number | null = null;
   206→    if (meta.token_usage) tokenUsageId = await createTokenUsage(db, meta.token_usage);
   207→    checkpointMeta = await db.checkpointMetadata.create({
   208→      data: {
   209→        checkpointId,
   210→        cliVersion:       meta.cli_version       ?? null,
   211→        branch:           meta.branch            ?? null,
   212→        strategy:         meta.strategy          ?? null,
   213→        checkpointsCount: meta.checkpoints_count ?? 0,
   214→        tokenUsageId,
   215→      },
   216→      select: { id: true },
   217→    });
   218→  } else {
   219→    await db.checkpointMetadata.update({
   220→      where: { checkpointId },
   221→      data: {
   222→        cliVersion:       meta.cli_version       ?? null,
   223→        branch:           meta.branch            ?? null,
   224→        strategy:         meta.strategy          ?? null,
   225→        checkpointsCount: meta.checkpoints_count ?? 0,
   226→      },
   227→    });
   228→  }
   229→
   230→  // files_touched → FilePath + join table
   231→  for (const filePath of meta.files_touched ?? []) {
   232→    const filePathId = await upsertFilePath(db, filePath);
   233→    await db.checkpointMetadataFilePath.upsert({
   234→      where: { checkpointMetadataId_filePathId: { checkpointMetadataId: checkpointMeta.id, filePathId } },
   235→      create: { checkpointMetadataId: checkpointMeta.id, filePathId },
   236→      update: {},
   237→    });
   238→  }
   239→
   240→  // Session sub-directories: 0/, 1/, …
   241→  const sessionDirs = readdirSync(checkpointDir)
   242→    .filter((e) => /^\d+$/.test(e) && statSync(join(checkpointDir, e)).isDirectory())
   243→    .sort((a, b) => parseInt(a) - parseInt(b));
   244→
   245→  for (const sessionDir of sessionDirs) {
   246→    const sessionPath    = join(checkpointDir, sessionDir);
   247→    const metadataFile   = join(sessionPath, "metadata.json");
   248→    const transcriptFile = join(sessionPath, "full.jsonl");
   249→    const contextFile    = join(sessionPath, "context.md");
   250→    const hashFile       = join(sessionPath, "content_hash.txt");
   251→    const promptFile     = join(sessionPath, "prompt.txt");
   252→
   253→    // Read actual hash content (not the file path)
   254→    const contentHash = existsSync(hashFile) ? readFileSync(hashFile, "utf8").trim() : null;
   255→
   256→    // Look up an existing SessionLink for this transcript path.
   257→    const transcriptVal = existsSync(transcriptFile) ? transcriptFile : null;
   258→    const existing = transcriptVal
   259→      ? await db.sessionLink.findFirst({
   260→          where: { checkpointMetadataId: checkpointMeta.id, transcript: transcriptVal },
   261→          select: { id: true, contentHash: true },
   262→        })
   263→      : null;
   264→
   265→    // If the content hash hasn't changed, this session is fully indexed — skip it.
   266→    if (existing && contentHash && existing.contentHash === contentHash) continue;
   267→
   268→    let sessionLink: { id: number };
   269→    if (existing) {
   270→      // Hash changed (JSONL grew) — update the stored hash and re-index.
   271→      sessionLink = await db.sessionLink.update({
   272→        where: { id: existing.id },
   273→        data: { contentHash },
   274→        select: { id: true },
   275→      });
   276→    } else {
   277→      sessionLink = await db.sessionLink.create({
   278→        data: {
   279→          checkpointMetadataId: checkpointMeta.id,
   280→          metadata:   existsSync(metadataFile)   ? metadataFile   : null,
   281→          transcript: transcriptVal,
   282→          context:    existsSync(contextFile)    ? contextFile    : null,
   283→          contentHash,
   284→          prompt:     existsSync(promptFile)     ? promptFile     : null,
   285→        },
   286→        select: { id: true },
   287→      });
   288→    }
   289→
   290→    if (transcriptVal) {
   291→      await indexFullJsonl(db, transcriptVal, sessionLink.id);
   292→    }
   293→
   294→    if (!existsSync(metadataFile)) continue;
   295→
   296→    const sessionMeta = JSON.parse(readFileSync(metadataFile, "utf8")) as SessionMeta;
   297→    const { session_id: sessionId } = sessionMeta;
   298→    if (!sessionId) continue;
   299→
   300→    // CheckpointSessionMetadata — create or update
   301→    let sessionRecord = await db.checkpointSessionMetadata.findUnique({
   302→      where: { checkpointId_sessionId: { checkpointId, sessionId } },
   303→      select: { id: true },
   304→    });
   305→
   306→    if (!sessionRecord) {
   307→      let sessionTokenUsageId: number | null = null;
   308→      if (sessionMeta.token_usage) {
   309→        sessionTokenUsageId = await createTokenUsage(db, sessionMeta.token_usage);
   310→      }
   311→      sessionRecord = await db.checkpointSessionMetadata.create({
   312→        data: {
   313→          checkpointId,
   314→          sessionId,
   315→          cliVersion:       sessionMeta.cli_version       ?? null,
   316→          strategy:         sessionMeta.strategy          ?? null,
   317→          createdAt:        sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   318→          branch:           sessionMeta.branch            ?? null,
   319→          checkpointsCount: sessionMeta.checkpoints_count ?? 0,
   320→          agent:            sessionMeta.agent             ?? null,
   321→          turnId:           sessionMeta.turn_id           ?? null,
   322→          tokenUsageId:     sessionTokenUsageId,
   323→        },
   324→        select: { id: true },
   325→      });
   326→    } else {
   327→      await db.checkpointSessionMetadata.update({
   328→        where: { checkpointId_sessionId: { checkpointId, sessionId } },
   329→        data: {
   330→          cliVersion: sessionMeta.cli_version ?? null,
   331→          strategy:   sessionMeta.strategy    ?? null,
   332→          createdAt:  sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   333→          branch:     sessionMeta.branch      ?? null,
   334→          agent:      sessionMeta.agent       ?? null,
   335→          turnId:     sessionMeta.turn_id     ?? null,
   336→        },
   337→      });
   338→    }
   339→
   340→    // files_touched for session
   341→    for (const filePath of sessionMeta.files_touched ?? []) {
   342→      const filePathId = await upsertFilePath(db, filePath);
   343→      await db.checkpointSessionMetadataFilePath.upsert({
   344→        where: {
   345→          checkpointSessionMetadataId_filePathId: {
   346→            checkpointSessionMetadataId: sessionRecord.id,
   347→            filePathId,
   348→          },
   349→        },
   350→        create: { checkpointSessionMetadataId: sessionRecord.id, filePathId },
   351→        update: {},
   352→      });
   353→    }
   354→
   355→    // initial_attribution
   356→    if (sessionMeta.initial_attribution) {
   357→      const ia = sessionMeta.initial_attribution as Record<string, unknown>;
   358→      const iaData = {
   359→        calculatedAt:    ia.calculated_at ? new Date(ia.calculated_at as string) : null,
   360→        agentLines:      Number(ia.agent_lines      ?? 0),
   361→        humanAdded:      Number(ia.human_added      ?? 0),
   362→        humanModified:   Number(ia.human_modified   ?? 0),
   363→        humanRemoved:    Number(ia.human_removed    ?? 0),
   364→        totalCommitted:  Number(ia.total_committed  ?? 0),
   365→        agentPercentage: Number(ia.agent_percentage ?? 0),
   366→      };
   367→      await db.initialAttribution.upsert({
   368→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   369→        create: { checkpointSessionMetadataId: sessionRecord.id, ...iaData },
   370→        update: iaData,
   371→      });
   372→    }
   373→
   374→    // summary
   375→    if (sessionMeta.summary) {
   376→      const sm = sessionMeta.summary;
   377→      const summaryRecord = await db.checkpointSessionSummary.upsert({
   378→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   379→        create: { checkpointSessionMetadataId: sessionRecord.id, intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   380→        update: { intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   381→        select: { id: true },
   382→      });
   383→
   384→      // Recreate child arrays on every index pass (preserve status/subSessionId on OpenItem)
   385→      await Promise.all([
   386→        db.frictionItem.deleteMany( { where: { checkpointSessionSummaryId: summaryRecord.id } }),
   387→        db.repoLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   388→        db.codeLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   389→        db.workflowItem.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   390→      ]);
   391→
   392→      const creates: Promise<unknown>[] = [];
   393→
   394→      if (sm.open_items?.length) {
   395→        // Look up prior statuses for this session so they survive new checkpoints being indexed.
   396→        // Fetch ALL non-open prior items (not just exact matches) so we can fuzzy-match rephrased items.
   397→        const priorItems = await db.openItem.findMany({
   398→          where: {
   399→            checkpointSessionSummary: {
   400→              checkpointSessionMetadata: { sessionId },
   401→            },
   402→            status: { notIn: ["open"] },
   403→          },
   404→          select: { text: true, status: true, subSessionId: true },
   405→          distinct: ["text"],
   406→          orderBy: { id: "desc" },
   407→        });
   408→
   409→        // Build a map for exact matches and a list for fuzzy fallback
   410→        const priorByText = new Map(priorItems.map((p) => [p.text, p]));
   411→
   412→        // Jaccard similarity on word tokens (case-insensitive, punctuation-stripped)
   413→        function tokenize(s: string): Set<string> {
   414→          return new Set(s.toLowerCase().replace(/[^\w\s]/g, " ").split(/\s+/).filter(Boolean));
   415→        }
   416→        function jaccardSimilarity(a: string, b: string): number {
   417→          const ta = tokenize(a);
   418→          const tb = tokenize(b);
   419→          let intersection = 0;
   420→          for (const w of ta) if (tb.has(w)) intersection++;
   421→          const union = ta.size + tb.size - intersection;
   422→          return union === 0 ? 0 : intersection / union;
   423→        }
   424→
   425→        function findBestPrior(text: string) {
   426→          // Exact match first
   427→          if (priorByText.has(text)) return priorByText.get(text);
   428→          // Fuzzy fallback: best Jaccard match above 0.5 threshold
   429→          let best: { text: string; status: string; subSessionId: string | null } | undefined;
   430→          let bestScore = 0.5; // minimum threshold
   431→          for (const prior of priorItems) {
   432→            const score = jaccardSimilarity(text, prior.text);
   433→            if (score > bestScore) { bestScore = score; best = prior; }
   434→          }
   435→          return best;
   436→        }
   437→
   438→        creates.push(...sm.open_items.map((text) => {
   439→          const prior = findBestPrior(text);
   440→          return db.openItem.upsert({
   441→            where: { checkpointSessionSummaryId_text: { checkpointSessionSummaryId: summaryRecord.id, text } },
   442→            create: {
   443→              checkpointSessionSummaryId: summaryRecord.id,
   444→              text,
   445→              status: prior?.status ?? "open",
   446→              subSessionId: prior?.subSessionId ?? null,
   447→            },
   448→            update: {},
   449→          });
   450→        }));
   451→        // Remove open items that no longer appear in the source
   452→        creates.push(
   453→          db.openItem.deleteMany({
   454→            where: { checkpointSessionSummaryId: summaryRecord.id, text: { notIn: sm.open_items } },
   455→          })
   456→        );
   457→      } else {
   458→        creates.push(db.openItem.deleteMany({ where: { checkpointSessionSummaryId: summaryRecord.id } }));
   459→      }
   460→      if (sm.friction?.length) {
