   496→/**
   497→ * Parse a full.jsonl transcript file and write normalized rows to the LogEvent
   498→ * family of tables.  Already-indexed events (matched by uuid or messageId) are
   499→ * skipped so this function is safe to call multiple times on the same file.
   500→ *
   501→ * @param sessionLinkId  Optional FK into SessionLink so events can be traced
   502→ *                       back to the checkpoint/session that produced them.
   503→ */
   504→export async function indexFullJsonl(
   505→  db: PrismaClient,
   506→  transcriptPath: string,
   507→  sessionLinkId?: number,
   508→): Promise<{ events: number }> {
   509→  const content = readFileSync(transcriptPath, "utf8");
   510→  const events = parseFullJsonl(content);
   511→
   512→  // Pre-load known uuids / messageIds to skip duplicates without per-row queries.
   513→  const [existingUuids, existingMessageIds] = await Promise.all([
   514→    db.logEvent.findMany({ where: { uuid: { not: null } }, select: { uuid: true } })
   515→      .then((rows) => new Set(rows.map((r) => r.uuid as string))),
   516→    db.logEvent.findMany({ where: { messageId: { not: null } }, select: { messageId: true } })
   517→      .then((rows) => new Set(rows.map((r) => r.messageId as string))),
   518→  ]);
   519→
   520→  let count = 0;
   521→
   522→  for (const event of events) {
   523→    // Deduplication: skip if this event was already indexed.
   524→    if (event.uuid && existingUuids.has(event.uuid)) continue;
   525→    if (event.messageId && existingMessageIds.has(event.messageId)) continue;
   526→
   527→    const msg = event.message as Record<string, unknown> | undefined;
   528→
   529→    const logEvent = await db.logEvent.create({
   530→      data: {
   531→        uuid:            event.uuid            ?? null,
   532→        messageId:       event.messageId       ?? null,
   533→        sessionId:       event.sessionId       ?? null,
   534→        parentUuid:      event.parentUuid      ?? null,
   535→        type:            event.type,
   536→        timestamp:       event.timestamp ? new Date(event.timestamp) : null,
   537→        cwd:             event.cwd             ?? null,
   538→        gitBranch:       event.gitBranch       ?? null,
   539→        version:         event.version         ?? null,
   540→        slug:            event.slug            ?? null,
   541→        isSidechain:     event.isSidechain     ?? null,
   542→        userType:        event.userType        ?? null,
   543→        toolUseId:       event.toolUseID       ?? null,
   544→        parentToolUseId: event.parentToolUseID ?? null,
   545→        requestId:       (event.requestId as string | undefined) ?? null,
   546→        data:            JSON.stringify(event),
   547→        sessionLinkId:   sessionLinkId         ?? null,
   548→      },
   549→      select: { id: true },
   550→    });
   551→
   552→    // ── user / assistant: parse message content blocks ──────────────────────
   553→    if ((event.type === "user" || event.type === "assistant") && msg) {
   554→      const role = (msg.role as string | undefined) ?? event.type;
   555→      const rawContent = msg.content;
   556→      const contentArray: Record<string, unknown>[] =
   557→        Array.isArray(rawContent)
   558→          ? (rawContent as Record<string, unknown>[])
   559→          : typeof rawContent === "string"
   560→          ? [{ type: "text", text: rawContent }]
   561→          : [];
   562→
   563→      for (let i = 0; i < contentArray.length; i++) {
   564→        const c = contentArray[i];
   565→        const cType = (c.type as string | undefined) ?? "text";
   566→
   567→        // Stringify tool_result content if it's not already a string.
   568→        let toolResultContent: string | null = null;
   569→        if (cType === "tool_result") {
   570→          toolResultContent =
   571→            typeof c.content === "string"
   572→              ? c.content
   573→              : c.content != null
   574→              ? JSON.stringify(c.content)
   575→              : null;
   576→        }
   577→
   578→        await db.logContent.create({
   579→          data: {
   580→            logEventId:        logEvent.id,
   581→            role,
   582→            contentIndex:      i,
   583→            contentType:       cType,
   584→            text:              (c.text as string | undefined)         ?? null,
   585→            thinking:          (c.thinking as string | undefined)     ?? null,
   586→            toolUseId:         (c.id as string | undefined)           // tool_use block
   587→                            ?? (c.tool_use_id as string | undefined)  // tool_result block
   588→                            ?? null,
   589→            toolName:          (c.name as string | undefined)         ?? null,
   590→            toolInput:         c.input != null ? JSON.stringify(c.input) : null,
   591→            toolResultContent,
   592→            isError:           (c.is_error as boolean | undefined)    ?? null,
   593→          },
   594→        });
   595→      }
   596→
   597→      // ── assistant: token usage ────────────────────────────────────────────
   598→      if (event.type === "assistant") {
   599→        const u = msg.usage as Record<string, unknown> | undefined;
   600→        if (u) {
   601→          await db.logUsage.create({
   602→            data: {
   603→              logEventId:               logEvent.id,
   604→              model:                    (msg.model as string | undefined)       ?? null,
   605→              stopReason:               (msg.stop_reason as string | undefined) ?? null,
   606→              inputTokens:              Number(u.input_tokens               ?? 0),
   607→              cacheCreationInputTokens: Number(u.cache_creation_input_tokens ?? 0),
   608→              cacheReadInputTokens:     Number(u.cache_read_input_tokens     ?? 0),
   609→              outputTokens:             Number(u.output_tokens               ?? 0),
   610→            },
   611→          });
   612→        }
   613→      }
   614→    }
   615→
   616→    // ── progress: hook_progress data ─────────────────────────────────────────
   617→    if (event.type === "progress") {
   618→      const d = event.data as Record<string, unknown> | undefined;
   619→      await db.logHookProgress.create({
   620→        data: {
   621→          logEventId: logEvent.id,
   622→          type:       (d?.type      as string | undefined) ?? null,
   623→          hookEvent:  (d?.hookEvent as string | undefined) ?? null,
   624→          hookName:   (d?.hookName  as string | undefined) ?? null,
   625→          command:    (d?.command   as string | undefined) ?? null,
   626→        },
   627→      });
   628→    }
   629→
   630→    // ── system events ─────────────────────────────────────────────────────────
   631→    if (event.type === "system") {
   632→      const e = event as Record<string, unknown>;
   633→      await db.logSystemEvent.create({
   634→        data: {
   635→          logEventId:            logEvent.id,
   636→          subtype:               (e.subtype               as string  | undefined) ?? null,
   637→          hookCount:             (e.hookCount              as number  | undefined) ?? null,
   638→          stopReason:            (e.stopReason             as string  | undefined) ?? null,
   639→          preventedContinuation: (e.preventedContinuation  as boolean | undefined) ?? null,
   640→          level:                 (e.level                 as string  | undefined) ?? null,
   641→          durationMs:            (e.durationMs             as number  | undefined) ?? null,
   642→        },
   643→      });
   644→    }
   645→
   646→    // Mark as seen so a duplicate later in the same file is also skipped.
   647→    if (event.uuid)      existingUuids.add(event.uuid);
   648→    if (event.messageId) existingMessageIds.add(event.messageId);
   649→
   650→    count++;
   651→  }
   652→
   653→  return { events: count };
   654→}
