   658→export async function indexAllCheckpointsV2(
   659→  db: PrismaClient,
   660→  rootDir: string,
   661→  onProgress?: (checkpointId: string) => void,
   662→  repoPath?: string,
   663→): Promise<{ checkpoints: number }> {
   664→  let totalCheckpoints = 0;
   665→
   666→  // Pre-fetch all checkpoint IDs that already have a git OID mapping so we
   667→  // can skip the per-checkpoint DB read inside saveGitOidMapping.
   668→  let mappedCheckpointIds: Set<string> | undefined;
   669→  if (repoPath) {
   670→    const rows = await db.checkpointIdGitOidJoin.findMany({ select: { checkpointId: true } });
   671→    mappedCheckpointIds = new Set(rows.map((r) => r.checkpointId));
   672→  }
   673→
   674→  const shards = readdirSync(rootDir)
   675→    .filter((e) => /^[0-9a-f]{2}$/i.test(e) && statSync(join(rootDir, e)).isDirectory());
   676→
   677→  for (const shard of shards) {
   678→    const shardPath = join(rootDir, shard);
   679→    const ids = readdirSync(shardPath)
   680→      .filter((e) => /^[0-9a-f]{10}$/i.test(e) && statSync(join(shardPath, e)).isDirectory());
   681→
   682→    for (const rest of ids) {
   683→      const checkpointId  = shard + rest;
   684→      const checkpointDir = join(shardPath, rest);
   685→      try {
   686→        await indexCheckpointV2(db, checkpointDir, checkpointId, repoPath, mappedCheckpointIds);
   687→        mappedCheckpointIds?.add(checkpointId); // keep set current for this pass
   688→        totalCheckpoints++;
   689→        onProgress?.(checkpointId);
   690→      } catch (err) {
   691→        process.stderr.write(`indexer-v2: skipping ${checkpointId}: ${err}\n`);
   692→      }
   693→    }
   694→  }
   695→
   696→  // Sync FTS index with any new LogContent rows added during this pass
   697→  await setupLogContentFts(db);
   698→  await syncLogContentFts(db);
   699→
   700→  return { checkpoints: totalCheckpoints };
   701→}
