   470→  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   471→    return {
   472→      intent:            summary.intent,
   473→      outcome:           summary.outcome,
   474→      openItems:         summary.openItems.map((r) => ({ id: r.id, text: r.text, status: r.status, subSessionId: r.subSessionId })),
   475→      friction:          summary.frictionItems.map((r) => r.text),
