   482→  const V2_SESSION_INCLUDE = {
   483→    summary: {
   484→      include: {
   485→        openItems:         true,
   486→        frictionItems:     true,
   487→        repoLearnings:     true,
   488→        codeLearnings:     true,
   489→        workflowLearnings: true,
