   505→
   506→      const checkpointIds = checkpoints.map((c) => c.checkpointId);
   507→
   508→      const sessions = await db.checkpointSessionMetadata.findMany({
   509→        where:   { checkpointId: { in: checkpointIds } },
   510→        orderBy: V2_SESSION_ORDER,
   511→        include: V2_SESSION_INCLUDE,
   512→      });
   513→
   514→      // Group sessions by checkpointId
   515→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   516→      for (const s of sessions) {
