   655→  // POST /api/sessions/spawn
   656→  app.post("/api/sessions/spawn", async (req, res) => {
   657→    const { prompt, cwd, openItemIds, parentSessionId } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[]; parentSessionId?: string };
   658→    if (!prompt || typeof prompt !== "string") {
   659→      res.status(400).json({ error: "prompt is required" });
   660→      return;
   661→    }
   662→    try {
   663→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   664→      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   665→      // Pass open item IDs and parent session so the SessionStart hook can link back
   666→      const envParts: string[] = [];
   667→      if (openItemIds?.length) envParts.push(`GOSSAMER_SPAWN_OPEN_ITEMS='${openItemIds.join(",")}'`);
   668→      if (parentSessionId) envParts.push(`GOSSAMER_SPAWN_PARENT_SESSION='${parentSessionId.replace(/'/g, "")}'`);
   669→      const envPrefix = envParts.length ? envParts.join(" ") + " " : "";
   670→      // Use AppleScript to open a new Terminal window running claude interactively
   671→      const script = [
   672→        `tell application "Terminal"`,
   673→        `  activate`,
   674→        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   675→        `end tell`,
   676→      ].join("\n");
   677→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   678→      // Mark selected open items as in_progress
   679→      if (openItemIds?.length) {
   680→        await db.openItem.updateMany({
   681→          where: { id: { in: openItemIds } },
   682→          data: { status: "in_progress" },
   683→        });
   684→      }
   685→      res.json({ started: true });
   686→    } catch (err) {
   687→      res.status(500).json({ error: String(err) });
   688→    }
   689→  });
