   692→  app.get("/api/search", async (req, res) => {
   693→    const q     = typeof req.query.q     === "string" ? req.query.q.trim()         : "";
   694→    const limit = typeof req.query.limit === "string" ? parseInt(req.query.limit)  : 50;
   695→    if (!q) { res.status(400).json({ error: "q is required" }); return; }
   696→    try {
   697→      const results = await searchLogContent(db, q, Math.min(limit, 200));
   698→      res.json(results);
   699→    } catch (err) {
   700→      // FTS5 MATCH errors (bad syntax) come back as exceptions
   701→      res.status(400).json({ error: String(err) });
   702→    }
   703→  });
   704→
   705→  // Create HTTP server and attach WebSocket server (shared port)
   706→  const httpServer = createServer(app);
   707→  const wss = new WebSocketServer({ server: httpServer });
   708→
   709→  // WebSocket change detection — poll every 2s, broadcast on new events or checkpoints
   710→  let lastMaxEventId: number | null = null;
   711→  let lastMaxCheckpointId: number | null = null;
   712→  const broadcast = () => {
   713→    const message = JSON.stringify({ type: "sessions_updated" });
   714→    for (const client of wss.clients) {
   715→      if (client.readyState === WebSocket.OPEN) {
   716→        client.send(message);
   717→      }
   718→    }
   719→  };
   720→  const poller = setInterval(async () => {
   721→    try {
   722→      const [latestEvent, latestCheckpoint] = await Promise.all([
   723→        db.event.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   724→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   725→      ]);
   726→      const currentEventId = latestEvent?.id ?? null;
   727→      const currentCheckpointId = latestCheckpoint?.id ?? null;
   728→      if (currentEventId !== lastMaxEventId || currentCheckpointId !== lastMaxCheckpointId) {
   729→        lastMaxEventId = currentEventId;
   730→        lastMaxCheckpointId = currentCheckpointId;
   731→        broadcast();
   732→      }
   733→    } catch {
   734→      // Non-fatal polling error — keep running
   735→    }
   736→  }, 2000);
   737→
   738→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   739→
   740→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   741→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   742→
   743→  if (repoDir) {
   744→    const WORKTREE_PATH = join(repoDir, ".gossamer", "checkpoints");
   745→    mkdirSync(join(repoDir, ".gossamer"), { recursive: true });
   746→
   747→    // Ensure worktree exists (reuse across restarts)
   748→    if (!existsSync(WORKTREE_PATH)) {
   749→      try {
   750→        // Prune stale worktree registration first, then re-add
   751→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   752→        execSync(
   753→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   754→          { stdio: "pipe" },
   755→        );
   756→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   757→      } catch (err) {
   758→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   759→      }
   760→    }
   761→
   762→    const runIndex = async () => {
   763→      if (!existsSync(WORKTREE_PATH)) return;
   764→      try {
   765→        // Fetch latest commits and advance the worktree to the branch tip
   766→        execSync(
   767→          `git -C ${JSON.stringify(WORKTREE_PATH)} fetch origin ${CHECKPOINT_BRANCH}`,
   768→          { stdio: "pipe" },
   769→        );
   770→        execSync(
   771→          `git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard FETCH_HEAD`,
   772→          { stdio: "pipe" },
   773→        );
   774→      } catch { /* non-fatal */ }
   775→      try {
   776→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH, undefined, repoDir);
   777→        if (checkpoints > 0) {
   778→          process.stderr.write(`checkpoint indexer: indexed ${checkpoints} checkpoints\n`);
   779→          broadcast();
   780→        }
   781→      } catch { /* non-fatal */ }
   782→    };
   783→
   784→    void runIndex();
   785→    checkpointPoller = setInterval(runIndex, 30_000);
   786→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   787→  }
   788→
   789→  // ── Shadow branch indexer ──────────────────────────────────────────────────
   790→
   791→  let shadowPoller: ReturnType<typeof setInterval> | null = null;
   792→
   793→  if (repoDir) {
   794→    const runShadowIndex = async () => {
   795→      try {
   796→        const { sessions } = await indexAllShadowBranches(db, repoDir);
   797→        if (sessions > 0) broadcast();
   798→      } catch { /* non-fatal */ }
   799→    };
   800→
   801→    void runShadowIndex();
   802→    shadowPoller = setInterval(runShadowIndex, 5_000);
   803→    process.stderr.write(`shadow indexer: polling every 5s (repo: ${repoDir})\n`);
   804→  }
   805→
   806→  // Graceful shutdown
   807→  const shutdown = () => {
   808→    clearInterval(poller);
   809→    if (checkpointPoller) clearInterval(checkpointPoller);
   810→    if (shadowPoller) clearInterval(shadowPoller);
   811→    httpServer.close();
   812→    process.exit(0);
   813→  };
   814→  process.on("SIGINT", shutdown);
   815→  process.on("SIGTERM", shutdown);
   816→
   817→  await new Promise<void>((resolve) => {
   818→    httpServer.listen(port, () => {
   819→      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   820→      resolve();
   821→    });
   822→  });
   823→}
