   253→export function subscribeToUpdates(onUpdate: () => void): () => void {
   254→  let ws: WebSocket | null = null;
   255→  let timer: ReturnType<typeof setTimeout> | null = null;
   256→  let closed = false;
   257→  let delay = 1000;
   258→
   259→  function connect() {
   260→    if (closed) return;
   261→    ws = new WebSocket(WS_URL);
   262→
   263→    ws.onopen = () => {
   264→      delay = 1000; // reset backoff on successful connection
   265→    };
   266→
   267→    ws.onmessage = (e) => {
   268→      try {
   269→        const msg = JSON.parse(e.data as string) as { type: string };
   270→        if (msg.type === "sessions_updated") onUpdate();
   271→      } catch {
   272→        // ignore malformed messages
   273→      }
   274→    };
   275→
   276→    ws.onclose = () => {
   277→      if (closed) return;
   278→      timer = setTimeout(() => {
   279→        delay = Math.min(delay * 2, 30000);
   280→        connect();
   281→      }, delay);
   282→    };
   283→
   284→    ws.onerror = () => {
   285→      ws?.close();
   286→    };
   287→  }
   288→
   289→  connect();
   290→
   291→  return () => {
   292→    closed = true;
   293→    if (timer !== null) clearTimeout(timer);
   294→    ws?.close();
   295→  };
   296→}
