          strategy: c.strategy,
          filesTouched: c.filesTouched ? (JSON.parse(c.filesTouched) as string[]) : [],
          tokenUsage: c.tokenUsage ? (JSON.parse(c.tokenUsage) as Record<string, unknown>) : null,
