        uuid: m.uuid,
        sessionId: m.sessionId,
        parentUuid: m.parentUuid,
        type: m.type,
        timestamp: m.timestamp?.toISOString() ?? null,
        gitBranch: m.gitBranch,
        slug: m.slug,
        planContent: m.planContent,
        toolUseId: m.toolUseId,
        parentToolUseId: m.parentToolUseId,
