   147→
   148→      if (toolResults.length > 0) {
   149→        for (const tr of toolResults) {
   150→          const failed = tr.isError === true;
   151→          result.push({
   152→            id: id--,
   153→            timestamp: ts,
   154→            event: failed ? "PostToolUseFailure" : "PostToolUse",
   155→            sessionId: sid,
   156→            blocked: false,
   157→            data: {
   158→              tool_use_id:   tr.toolUseId,
   159→              tool_response: !failed ? (tr.toolResultContent ?? "") : undefined,
   160→              error:          failed ? (tr.toolResultContent ?? "") : undefined,
   161→            },
   162→            summary: null, keywords: [],
   163→          });
   164→        }
   165→      } else if (textBlocks.length > 0) {
   166→        const prompt = textBlocks.map((b) => b.text ?? "").join("\n\n");
   167→        result.push({ id: id--, timestamp: ts, event: "UserPromptSubmit", sessionId: sid, blocked: false, data: { prompt }, summary: null, keywords: [] });
   168→      }
   169→
   170→    } else if (le.type === "assistant") {
   171→      const toolUses   = le.contents.filter((c) => c.contentType === "tool_use");
   172→      const textBlocks = le.contents.filter((c) => c.contentType === "text");
   173→
   174→      if (textBlocks.length > 0) {
   175→        lastAssistantText = textBlocks.map((b) => b.text ?? "").filter(Boolean).join("\n\n");
   176→      }
   177→
   178→      for (const tu of toolUses) {
   179→        result.push({
   180→          id: id--,
   181→          timestamp: ts,
   182→          event: "PreToolUse",
   183→          sessionId: sid,
   184→          blocked: false,
   185→          data: { tool_name: tu.toolName ?? "?", tool_use_id: tu.toolUseId, tool_input: tu.toolInput },
   186→          summary: null, keywords: [],
   187→        });
   188→      }
   189→
   190→    } else if (le.type === "system" && le.systemData?.subtype === "stop_hook_summary") {
   191→      result.push({
   192→        id: id--,
   193→        timestamp: ts,
   194→        event: "Stop",
   195→        sessionId: sid,
   196→        blocked: le.systemData.preventedContinuation ?? false,
   197→        data: { last_assistant_message: lastAssistantText ?? "", reason: le.systemData.stopReason ?? "" },
   198→        summary: null, keywords: [],
   199→      });
   200→      lastAssistantText = null;
   201→    }
   202→  }
   203→
   204→  // Flush any trailing assistant text that had no stop event
   205→  if (lastAssistantText !== null && filtered.length > 0) {
   206→    const last = filtered[filtered.length - 1];
   207→    result.push({
   208→      id: id--,
   209→      timestamp: last.timestamp ?? "",
   210→      event: "Stop",
   211→      sessionId: last.sessionId ?? "",
   212→      blocked: false,
   213→      data: { last_assistant_message: lastAssistantText, reason: "" },
   214→      summary: null, keywords: [],
   215→    });
   216→  }
   217→
   218→  return result;
   219→}
