   221→function groupEvents(events: Event[]): DisplayItem[] {
   222→  const postMap = new Map<string, Event>();
   223→  for (const event of events) {
   224→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
   225→      const d = event.data as Record<string, unknown>;
   226→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   227→      if (id) postMap.set(id, event);
   228→    }
   229→  }
   230→
   231→  type RawItem =
   232→    | { kind: "event"; event: Event }
   233→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
   234→
   235→  const raw: RawItem[] = [];
   236→  const consumed = new Set<number>();
   237→
   238→  for (const event of events) {
   239→    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
   240→    if (event.event === "PreToolUse") {
   241→      const d = event.data as Record<string, unknown>;
   242→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   243→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
   244→      if (post) consumed.add(post.id);
   245→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
   246→      continue;
   247→    }
   248→    raw.push({ kind: "event", event });
   249→  }
   250→
   251→  const isGroupable = (item: RawItem) =>
   252→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
   253→
   254→  const result: DisplayItem[] = [];
   255→  let i = 0;
   256→  while (i < raw.length) {
   257→    if (isGroupable(raw[i])) {
   258→      const group: ToolUseData[] = [];
   259→      while (i < raw.length && isGroupable(raw[i])) {
   260→        const item = raw[i];
   261→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
   262→        i++;
   263→      }
   264→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
   265→    } else {
   266→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
   267→      i++;
   268→    }
   269→  }
   270→  return result;
   271→}
