   398→        const grouped = groupEvents(logEventsToEvents(logEvs));
   399→        const merged: DisplayItem[] = [];
   400→        let cpIdx = 0;
   401→        const sortedCps = [...checkpoints].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   402→        const latest = sortedCps[sortedCps.length - 1] ?? null;
   403→        setLatestCheckpoint(latest);
   404→        setOpenItems(latest?.summary?.openItems ?? []);
   405→
   406→        for (const item of grouped) {
   407→          const itemTime = item.kind === "event" ? item.event.timestamp : item.kind === "toolGroup" ? item.tools[0]?.pre.timestamp ?? "" : "";
   408→          while (cpIdx < sortedCps.length && (sortedCps[cpIdx].createdAt ?? "") <= itemTime) {
   409→            merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
