   476→                            e.currentTarget.checked ? next.add(i) : next.delete(i);
   477→                            return next;
   478→                          });
   479→                        }}
   480→                        onClick={(e) => e.stopPropagation()}
   481→                        style={{ marginTop: 2, flexShrink: 0 }}
   482→                      />
   483→                    ) : (
