   501→                            fw={item.status === s ? 700 : undefined}
   502→                            onClick={async () => {
   503→                              await updateOpenItemStatus(item.id, s).catch(() => undefined);
   504→                              setOpenItems((prev) => prev.map((it) => it.id === item.id ? { ...it, status: s } : it));
   505→                              if (s !== "open") setSelectedItems((prev) => { const n = new Set(prev); n.delete(i); return n; });
   506→                            }}
   507→                          >
   508→                            {s === "in_progress" ? "in progress" : s === "na" ? "n/a" : s}
   509→                          </Menu.Item>
   510→                        ))}
   511→                      </Menu.Dropdown>
   512→                    </Menu>
   513→                    <Text size="xs" lh={1.5} c={selectable ? undefined : "dimmed"} style={{ cursor: "default" }}>{item.text}</Text>
   514→                  </Group>
