   536→                          setSelectedItems(new Set());
   537→                        } finally {
   538→                          setSpawning(false);
   539→                        }
   540→                      }}
   541→                    >
   542→                      →
   543→                    </ActionIcon>
   544→                  </Tooltip>
   545→                </Group>
   546→              )}
   547→            </Box>
